class Task:
    def __init__(self, name, done=False):
        self.name = name
        self.done = done

    def label(self):
        if self.done:
            prefix = "[x] "
        else:
            prefix = "[ ] "
        return prefix + self.name


def count_open(tasks):
    total = 0
    for task in tasks:
        if not task.done:
            total += 1
    return total


def load_tasks(path):
    tasks = []
    with open(path, "r") as file:
        for line in file:
            line = line.strip()
            if line == "":
                continue
            name, status = line.split("|")
            done = status == "done"
            tasks.append(Task(name, done))
    return tasks


def build_report(tasks):
    total = len(tasks)
    done_count = 0
    for task in tasks:
        if task.done:
            done_count += 1
    open_count = count_open(tasks)
    return f"Total: {total}\nDone: {done_count}\nOpen: {open_count}"
